// Type decalrations for the entire library
// If you don't know what this is, you can ignore it.

declare module "*.html" {
	const value: string;
	export default value;
}

declare module "*.css?raw" {
	const value: string;
	export default value;
}


declare module "*.scss?raw" {
	const value: string;
	export default value;
}


declare module "*.html?raw" {
	const value: string;
	export default value;
}
